mapper.update:
INSERT INTO TB_PROP_CATEGORY (
    CAT_CD, UPR_CAT_CD, CAT_NM, CAT_LVL, SORT_ORDER
  , USE_YN, BIGO, DEL_YN, CRE_USR_CD, CRE_DTM, UPD_USR_CD, UPD_DTM
) VALUES (
    #{catCd}, #{uprCatCd}, #{catNm}, #{catLvl}, #{sortOrder}
  , #{useYn}, #{bigo}, 'N', #{ssnUsrCd}, NOW(), #{ssnUsrCd}, NOW()
)
ON DUPLICATE KEY UPDATE
    UPR_CAT_CD  = #{uprCatCd}
  , CAT_NM      = #{catNm}
  , CAT_LVL     = #{catLvl}
  , SORT_ORDER  = #{sortOrder}
  , USE_YN      = #{useYn}
  , BIGO        = #{bigo}
  , UPD_USR_CD  = #{ssnUsrCd}
  , UPD_DTM     = NOW()

mapper.delete:
DELETE FROM TB_PROP_CATEGORY
 WHERE CAT_CD = #{catCd}
    OR UPR_CAT_CD = #{catCd}
    OR UPR_CAT_CD IN (SELECT t.CAT_CD FROM (SELECT CAT_CD FROM TB_PROP_CATEGORY WHERE UPR_CAT_CD = #{catCd}) t)

mapper.select:
SELECT CONCAT(#{uprCatCd}, '_', LPAD(IFNULL(MAX(
    CAST(SUBSTRING_INDEX(CAT_CD, '_', -1) AS UNSIGNED)
), 0) + 1, 3, '0'))
  FROM TB_PROP_CATEGORY
 WHERE UPR_CAT_CD = #{uprCatCd}
   AND DEL_YN = 'N'
